#include <bits/stdc++.h>
using namespace std;
int n,m,a[302],dp[302][302];
vector<int> g[302];
void dfs(int x){
    int len=g[x].size();
    for(int i=1;i<=m;i++)
        dp[x][i]=a[x];
    for(int i=0;i<len;i++){
        dfs(g[x][i]);
        for(int j=m;j>=2;j--)
            for(int k=1;k<j;k++)
                dp[x][j]=max(dp[x][j],dp[x][j-k]+dp[g[x][i]][k]);
    }
}
int main(){
    scanf("%d%d",&n,&m);
    m++;
    for(int i=1;i<=n;i++){
        int f;
        scanf("%d%d",&f,&a[i]);
        g[f].push_back(i);
    }
    dfs(0);
    printf("%d",dp[0][m]);
    return 0;
}
